#include <bits/stdc++.h>
using namespace std;
int r,c,sx,sy,a[55][55],dx[]={-1,1,0,0},dy[]={0,0,-1,1},vis[55][55],ans;
string s[55];
struct node
{
	int x,y,z;
};
queue<node> q;
void bfs()
{
	while(!q.empty())
	{
		node t=q.front();
		q.pop();
		for(int i=0;i<4;i++)
		{
			int nx=t.x+dx[i],ny=t.y+dy[i];
			if(nx>=1&&ny>=1&&nx<=r&&ny<=c&&a[nx][ny]==0x3f3f3f3f&&s[nx][ny]!='X'&&s[nx][ny]!='D'&&vis[nx][ny]==0)
			{
				a[nx][ny]=t.z+1;
				q.push(node{nx,ny,t.z+1});
                vis[nx][ny]=1;
			}
		}
	}
}
void bfs2()
{
    memset(vis,0,sizeof(vis));
	q.push(node{sx,sy,0});
	while(!q.empty())
	{
		node t=q.front();
		q.pop();
		for(int i=0;i<4;i++)
		{

			int nx=t.x+dx[i],ny=t.y+dy[i];
			if(nx>=1&&ny>=1&&nx<=r&&ny<=c&&s[nx][ny]!='X'&&a[nx][ny]>t.z+1&&vis[nx][ny]==0)
			{
				if(s[nx][ny]=='D')
				{
					ans=t.z+1;
					return ;
				}
				q.push(node{nx,ny,t.z+1});
                vis[nx][ny]=1;
			}
		}
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>r>>c;
	memset(a,0x3f,sizeof(a));
	for(int i=1;i<=r;i++)
	{
		cin>>s[i];
		s[i]=' '+s[i];
		for(int j=1;j<=c;j++)
		{
			if(s[i][j]=='S')
			{
				sx=i;
				sy=j;
			}
			else if(s[i][j]=='*')
			{
				a[i][j]=0;
				q.push(node{i,j,0});
                vis[i][j]=1;
			}
		}
	}
	bfs();
	bfs2();
	if(ans==0) cout<<"KAKTUS";
	else cout<<ans;
	return 0;
}
